+        let dir = tempfile::tempdir().unwrap();
+        let path = dir.path().join("schema_only_fast_path_iouring.db");
+        let path_str = path.to_string_lossy().into_owned();
+        Connection::open(path_str.clone()).unwrap();
+        let conn = Connection::open_schema_only(path_str).unwrap();
+        match &conn.pager {
+            PagerBackend::IoUring(pager) => {
+                assert!(pager.is_single_connection_cache_fast_path_enabled());
+            }
